using System;
using System.Collections;
using UnityEngine;

/// <summary>
/// Restrição de posição na água para um ataque (Enemy Creator — Etapa 3.2).
/// Só relevante quando o ataque tem "usableInWater" activo.
/// </summary>
public enum WaterAttackPosition
{
    /// <summary>Sem restrição: usável em qualquer profundidade.</summary>
    Qualquer,

    /// <summary>Só usável com o inimigo à superfície (IsAtSurface).</summary>
    SoSuperficie,

    /// <summary>Só usável com o inimigo submerso (IsSubmerged).</summary>
    SoSubmerso
}

/// <summary>
/// Classe-base de um ataque de inimigo (Enemy Creator — Etapa 2.1).
///
/// Cada subclasse [System.Serializable] (prefixo "Attack_") representa um tipo
/// de ataque e é adicionada à lista <see cref="EnemyAttackController.attacks"/>
/// via PolymorphicListDrawer — mesmo padrão de EnemyCondition/NpcAction/NpcCondition.
///
/// Ciclo de vida de um ataque, gerido por EnemyAttackController:
///
/// 1. <see cref="CanUse"/> — true se este ataque pode ser escolhido agora
///    (alcance, ambiente, linha de visão, cooldown). O controller escolhe, entre
///    os ataques disponíveis, o de maior <see cref="priority"/>.
/// 2. EnemyState.PreparandoAtaque durante <see cref="prepTime"/> — telegraph/aviso
///    (EnemyFeedback, Etapa 7.1, pode reagir a este estado para mostrar ícones/VFX).
/// 3. EnemyState.Atacando — corre <see cref="Execute"/> (coroutine). É aqui que o
///    dano/efeito acontece.
/// 4. EnemyState.Recuperando durante <see cref="recoveryTime"/>.
/// 5. Volta a Perseguindo (se ainda houver alvo) e fica indisponível durante
///    <see cref="cooldown"/> (controlado por <see cref="availableAt"/>).
/// </summary>
[System.Serializable]
public abstract class EnemyAttack
{
    [Header("Identidade")]
    [Tooltip("Nome usado em logs/feedback (ex: \"Garra\", \"Investida\").")]
    public string attackName = "Ataque";

    [Header("Combate")]
    [Tooltip("Dano causado ao player, em corações (PlayerProgress.Damage).")]
    public int damage = 1;

    [Tooltip("Força de empurrão aplicada ao player ao ser atingido (0 = sem empurrão).")]
    public float knockbackForce = 0f;

    [Header("Selecção")]
    [Tooltip("Distância máxima ao alvo para este ataque poder ser escolhido.")]
    public float range = 3f;

    [Tooltip("Distância mínima ao alvo (útil para ataques à distância que não devem disparar muito perto).")]
    public float minRange = 0f;

    [Tooltip("Exige linha de visão directa ao alvo (sem 'Bloqueadores de Linha de Visão' entre o inimigo e o alvo) para poder ser escolhido.")]
    public bool requiresLineOfSight = false;

    [Tooltip("Prioridade na escolha entre ataques disponíveis no mesmo instante (maior = preferido).")]
    public int priority = 0;

    [Header("Onde Pode Ser Usado")]
    public bool usableOnGround = true;
    public bool usableInAir = false;
    public bool usableInWater = false;

    [Header("Água (Etapa 3.2)")]
    [Tooltip("Restrição de posição na água: só à superfície / só submerso / qualquer. Ignorado fora de água (ver 'usableInWater').")]
    public WaterAttackPosition waterPosition = WaterAttackPosition.Qualquer;

    [Tooltip("Velocidade de nado do inimigo DURANTE este ataque (0 = não se desloca). Usada por ataques aquáticos que se movem (ex: Investida Aquática) via ctx.SwimTowardsTarget.")]
    [Min(0f)]
    public float attackSwimSpeed = 0f;

    [Header("Tempos (segundos)")]
    [Tooltip("Telegraph: aviso antes do ataque ficar perigoso (EnemyState.PreparandoAtaque).")]
    public float prepTime = 0.3f;

    [Tooltip("Recuperação após o ataque, antes de poder agir de novo (EnemyState.Recuperando).")]
    public float recoveryTime = 0.4f;

    [Tooltip("Tempo mínimo entre usos deste ataque.")]
    public float cooldown = 1.5f;

    /// <summary>
    /// Tempo (Time.time) a partir do qual este ataque volta a estar disponível.
    /// Gerido por EnemyAttackController — não editar no Inspector.
    /// </summary>
    [NonSerialized] public float availableAt;

    /// <summary>
    /// True se este ataque pode ser escolhido agora: alcance
    /// (minRange &lt;= distância &lt;= range), ambiente
    /// (usableOnGround/InAir/InWater — ver <see cref="EnemyAttackController.EnvironmentAllows"/>),
    /// linha de visão (se exigida) e cooldown (<see cref="availableAt"/>).
    /// Subclasses podem adicionar condições extra chamando
    /// "base.CanUse(ctx) &amp;&amp; ...".
    /// </summary>
    public virtual bool CanUse(EnemyAttackController ctx)
    {
        if (Time.time < availableAt) return false;

        var target = ctx.Target;
        if (target == null) return false;

        float dist = Vector2.Distance(ctx.transform.position, target.position);
        if (dist > range || dist < minRange) return false;

        if (!ctx.EnvironmentAllows(this)) return false;
        if (!ctx.WaterPositionAllows(this)) return false;
        if (requiresLineOfSight && !ctx.HasLineOfSight(target)) return false;

        return true;
    }

    /// <summary>
    /// Executa a fase activa do ataque (EnemyState.Atacando). Corre como
    /// coroutine — pode "yield return" para ataques com duração (laser,
    /// corrente, investida, etc). Ao terminar, o controller marca o cooldown e
    /// passa o inimigo a Recuperando.
    /// </summary>
    public abstract IEnumerator Execute(EnemyAttackController ctx);
}
